# Definition for a binary tree node.
class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def lowestCommonAncestor(self, root: 'TreeNode', p: 'TreeNode', q: 'TreeNode') -> 'TreeNode':
        # If both p and q are smaller than the current root,
        # the LCA must be in the left subtree.
        if root.val > p.val and root.val > q.val:
            return self.lowestCommonAncestor(root.left, p, q)
        # If both p and q are larger than the current root,
        # the LCA must be in the right subtree.
        elif root.val < p.val and root.val < q.val:
            return self.lowestCommonAncestor(root.right, p, q)
        # Otherwise, the current root is the LCA. This covers cases where:
        # 1. p is in the left subtree and q is in the right subtree (or vice versa).
        # 2. One of the nodes (p or q) is the root itself.
        else:
            return root
